// Assemble the LLM brief from the four upstream responses.
// We deliberately trim every block to small payloads so the reasoning
// model (Qwen3.5-122B-A10B) doesn't drown in tokens — the DSL catalog
// is authoritative; lessons + RAG hits are inspiration.
const catalog    = $('GET DSL catalog').first()?.json || {};
const leaderRows = ($('GET leaderboard (7d)').first()?.json?.rows || []).slice(0, 25);
const universe   = ($('GET universe (7d)').first()?.json?.symbols || []).slice(0, 80);
const analyses   = ($('RAG: asset analyses').first()?.json?.hits || []).slice(0, 8);
const relations  = ($('RAG: relations').first()?.json?.hits || []).slice(0, 8);
const lessons    = ($('RAG: strategy lessons').first()?.json?.hits || []).slice(0, 6);

const trimmedAnalyses = analyses.map(h => ({
  symbol:      h.symbol,
  confidence:  h.confidence,
  summary:     (h.summary || '').slice(0, 220),
  keywords:    (h.keywords || []).slice(0, 6),
}));
const trimmedRelations = relations.map(h => ({
  theme:      h.theme,
  mechanism:  h.mechanism,
  confidence: h.confidence,
  symbols:    (h.symbols || []).slice(0, 8),
  sectors:    (h.sectors || []).slice(0, 6),
  summary:    (h.summary || '').slice(0, 180),
}));
const trimmedLessons = lessons.map(h => ({
  strategy: h.strategy,
  outcome:  h.outcome,
  pnl_pct:  h.pnl_pct,
  lesson:   (h.lesson || '').slice(0, 260),
}));
const leaderboardSummary = leaderRows.map(r => ({
  name:           r.name,
  kind:           r.kind,
  status:         r.status,
  window_pnl_pct: r.window_pnl_pct,
  window_cycles:  r.window_cycles,
  retire_reason:  (r.retire_reason || '').slice(0, 120),
}));

if (!universe.length) {
  return [{ json: { skip: true, reason: 'universe empty (no recent ticks)' } }];
}

const now      = new Date().toISOString().slice(0, 19).replace('T','-').replace(/:/g,'');
const seed     = Math.random().toString(36).slice(2, 6);
const basename = 'gen_' + now + '_' + seed;

return [{ json: {
  skip: false,
  catalog,
  basename,
  universe,
  brief: {
    leaderboard:  leaderboardSummary,
    analyses:     trimmedAnalyses,
    relations:    trimmedRelations,
    lessons:      trimmedLessons,
  },
} }];

// Verifier: parse JSON, validate every proposal against the catalog
// + universe. Emits one item per accepted proposal so SplitInBatches
// (or built-in per-item handling) can post each to /strategies/propose.
const brief    = $('Build brief').item.json;
const catalog  = brief.catalog || {};
const universe = new Set((brief.universe || []).map(s => String(s).toUpperCase()));
const allowedSignals = new Set(Object.keys(catalog.signals || {}));
const allowedOps     = new Set(catalog.ops || []);
const allowedActions = new Set(catalog.actions || []);
const allowedSizing  = new Set(catalog.sizing || []);
const limits         = catalog.limits || { max_rules: 12, max_predicates_per_rule: 8, max_nesting_depth: 4 };
const basename       = brief.basename || ('gen_' + Date.now());

const llmResp = $json;
let raw = '';
let parsed = null;
try {
  raw = String(llmResp?.choices?.[0]?.message?.content || '').trim();
  const m = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(m ? m[0] : raw);
} catch (e) {
  return [{ json: { skip: true, reason: 'invalid JSON from LLM', raw: raw.slice(0, 800) } }];
}
const proposals = Array.isArray(parsed?.proposals) ? parsed.proposals : [];
if (!proposals.length) {
  return [{ json: { skip: true, reason: 'no proposals returned', raw: raw.slice(0, 800) } }];
}

function validateWhen(node, depth) {
  if (depth > limits.max_nesting_depth) return 'nesting too deep';
  if (!node || typeof node !== 'object') return 'predicate not object';
  if (Array.isArray(node.all) || Array.isArray(node.any)) {
    const key  = node.all ? 'all' : 'any';
    const kids = node[key];
    if (!Array.isArray(kids) || !kids.length) return key + ' empty';
    if (kids.length > limits.max_predicates_per_rule) return key + ' too many predicates';
    for (const k of kids) {
      const err = validateWhen(k, depth + 1);
      if (err) return err;
    }
    return null;
  }
  if (!allowedSignals.has(node.signal)) return 'signal ' + node.signal + ' not allowed';
  if (!allowedOps.has(node.op))         return 'op ' + node.op + ' not allowed';
  if (typeof node.value === 'undefined') return 'value missing';
  return null;
}

function collectSymbolRefs(spec) {
  const refs = new Set();
  if (spec.universe_filter && Array.isArray(spec.universe_filter.symbols)) {
    for (const s of spec.universe_filter.symbols) refs.add(String(s).toUpperCase());
  }
  for (const r of (spec.rules || [])) {
    if (Array.isArray(r.symbols)) for (const s of r.symbols) refs.add(String(s).toUpperCase());
  }
  return refs;
}

const accepted = [];
const rejected = [];
for (let i = 0; i < proposals.length; i++) {
  const p = proposals[i] || {};
  const errors = [];
  if (!Array.isArray(p.rules) || !p.rules.length)        errors.push('rules empty');
  if (p.rules && p.rules.length > limits.max_rules)      errors.push('too many rules');
  const atypes = Array.isArray(p.asset_types) ? p.asset_types : ['stock','crypto'];
  for (const a of atypes) if (a !== 'stock' && a !== 'crypto') errors.push('bad asset_type ' + a);
  let hasBuy = false;
  const seenIds = new Set();
  for (let j = 0; j < (p.rules || []).length; j++) {
    const r = p.rules[j];
    if (!r || typeof r !== 'object')                     { errors.push('rule '+j+' not object'); continue; }
    if (!allowedActions.has(r.action))                    errors.push('rule '+j+'.action invalid');
    if (r.action === 'buy')                              hasBuy = true;
    if (r.id) {
      if (seenIds.has(r.id))                              errors.push('rule '+j+'.id duplicate');
      seenIds.add(r.id);
    }
    const whenErr = r.when ? validateWhen(r.when, 0) : 'when missing';
    if (whenErr)                                          errors.push('rule '+j+'.when: ' + whenErr);
    const sizing = r.sizing || { mode: 'max_position_frac' };
    if (!allowedSizing.has(sizing.mode))                  errors.push('rule '+j+'.sizing.mode invalid');
    if (sizing.mode === 'fixed_eur' && !(Number(sizing.eur) > 0)) errors.push('rule '+j+'.sizing.eur missing');
  }
  if (!hasBuy)                                            errors.push('no buy rule');
  if (p.max_position_frac !== undefined && p.max_position_frac !== null) {
    const mpf = Number(p.max_position_frac);
    if (!(mpf > 0 && mpf <= 1))                           errors.push('max_position_frac out of range');
  }
  // Universe check: any referenced symbol must be in the live universe.
  const refs = collectSymbolRefs(p);
  for (const s of refs) if (!universe.has(s)) errors.push('symbol ' + s + ' not in universe');

  if (errors.length) {
    rejected.push({ index: i, errors: errors.slice(0, 5) });
    continue;
  }
  const name = basename + '_' + (i + 1);
  accepted.push({ json: {
    skip: false,
    name,
    source: {
      version: 1,
      description: String(p.description || 'LLM-generated DSL strategy').slice(0, 200),
      asset_types: atypes,
      max_position_frac: p.max_position_frac ?? null,
      universe_filter:   p.universe_filter || null,
      rules:             p.rules,
      generated_at:      new Date().toISOString(),
      generator:         'n8n:12-finance-strategy-genesis',
    },
  } });
}
if (!accepted.length) {
  return [{ json: { skip: true, reason: 'all proposals rejected', rejected, raw: raw.slice(0, 600) } }];
}
return accepted;
